(game "Robust Soft Rooster"
    (players 2)
    (equipment 
        (board (square 5))
    ) 

    (rules 
        (play
            (repeat (P1 P2)
                (place 
                    (destination empty)
                    (result 
                        (or 
                            (not (adjacent occupied))
                            (exists (adjacent empty))
                        )
                    )
                )
